// src/pages/ngo/admin/DetailPage.jsx
import PageHeader from "../../../components/shared/PageHeader";
import Badge      from "../../../components/shared/Badge";
import { ngos, funds } from "../../../data/mockData";

const fmt = (n) => n?.toLocaleString() ?? "–";
const ngo  = ngos[0];
const ngoFunds = funds.filter((f) => f.ngo === ngo.id);

export default function DetailPage() {
  return (
    <div>
      <PageHeader title="NGO Details" desc="Detailed view of your organization" />
      <div className="grid-2">
        {/* Info card */}
        <div className="card">
          <div style={{ display:"flex", gap:14, marginBottom:18, flexWrap:"wrap" }}>
            <div style={{ width:52, height:52, borderRadius:14, background:"linear-gradient(135deg,var(--purple),#7c3aed)", display:"flex", alignItems:"center", justifyContent:"center", fontSize:22, flexShrink:0 }}>🌱</div>
            <div>
              <div style={{ fontSize:16, fontWeight:800 }}>{ngo.name}</div>
              <div style={{ fontSize:12, color:"var(--text-3)", fontFamily:"'DM Mono',monospace" }}>{ngo.id} · {ngo.focus}</div>
              <div style={{ marginTop:6 }}><Badge type={ngo.verified ? "green" : "red"}>{ngo.verified ? "Verified" : "Pending"}</Badge></div>
            </div>
          </div>
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10 }}>
            {[["Admin", ngo.admin],["Focus", ngo.focus],["Active Funds", ngo.funds],["Total Raised","9,640 ◈"]].map(([k,v]) => (
              <div key={k} style={{ background:"var(--bg-surface)", borderRadius:"var(--radius)", padding:"10px 12px" }}>
                <div style={{ fontSize:10, color:"var(--text-3)", fontFamily:"'DM Mono',monospace", textTransform:"uppercase", letterSpacing:1, marginBottom:4 }}>{k}</div>
                <div style={{ fontSize:13, fontWeight:600 }}>{v}</div>
              </div>
            ))}
          </div>
        </div>

        {/* Funds summary */}
        <div className="card">
          <div className="card-title" style={{ marginBottom:14 }}>Fund Summary</div>
          {ngoFunds.map((f) => {
            const pct = Math.round((f.raised / f.target) * 100);
            return (
              <div key={f.id} style={{ marginBottom:14 }}>
                <div style={{ display:"flex", justifyContent:"space-between", marginBottom:4, flexWrap:"wrap", gap:4 }}>
                  <span style={{ fontSize:13, fontWeight:600 }}>{f.name}</span>
                  <Badge type={f.status==="open"?"green":"red"}>{f.status}</Badge>
                </div>
                <div style={{ fontSize:12, color:"var(--text-3)", marginBottom:6 }}>{fmt(f.raised)} / {fmt(f.target)} tokens</div>
                <div className="progress-track"><div className="progress-fill" style={{ width:`${pct}%` }} /></div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}
